import React from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const HtmlCertificate = ({ certificate, onDownload }) => {
  const certificateRef = React.useRef(null);

  const downloadAsPDF = async () => {
    if (!certificateRef.current) return;
    
    try {
      const canvas = await html2canvas(certificateRef.current, {
        scale: 5, // 更高分辨率
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });
      
      const imgData = canvas.toDataURL('image/png', 1.0);
      
      // A4 尺寸
      const pdf = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4',
        compress: false // 不压缩以保持质量
      });
      
      const imgWidth = 297; // A4 宽度
      const imgHeight = 210; // A4 高度
      
      pdf.addImage(imgData, 'PNG', 0, 0, imgWidth, imgHeight, '', 'FAST');
      pdf.save(`${certificate.name}_${certificate.certificateId}.pdf`);
      
      if (onDownload) {
        onDownload();
      }
    } catch (error) {
      console.error('下载证书失败:', error);
      alert('生成PDF时出错，请稍后再试');
    }
  };

  // 增加下载图片功能
  const downloadAsImage = async () => {
    if (!certificateRef.current) return;
    
    try {
      const canvas = await html2canvas(certificateRef.current, {
        scale: 5, // 更高分辨率 
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });
      
      // 使用最高质量创建PNG
      const imgData = canvas.toDataURL('image/png', 1.0);
      
      // 创建下载链接
      const link = document.createElement('a');
      link.href = imgData;
      link.download = `${certificate.name}_${certificate.certificateId}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      
      if (onDownload) {
        onDownload();
      }
    } catch (error) {
      console.error('下载图片失败:', error);
      alert('生成图片时出错，请稍后再试');
    }
  };

  return (
    <div className="flex flex-col items-center">
      {/* 证书HTML模板 */}
      <div 
        ref={certificateRef}
        className="relative bg-white border-4 border-black"
        style={{ 
          width: '800px', 
          height: '600px',
          fontFamily: 'Arial, sans-serif',
          color: '#000000',
          boxShadow: '0 4px 10px rgba(0,0,0,0.5)',
          overflow: 'hidden'
        }}
      >
        {/* 纯色背景 */}
        <div className="absolute inset-0 bg-white"></div>
        
        {/* 证书边框 - 使用纯黑色边框确保最大对比度 */}
        <div className="absolute inset-0 border-8 border-black m-2 z-10"></div>
        
        {/* 额外的装饰性边框 */}
        <div className="absolute inset-0 border-4 border-black m-6 z-20"></div>
        
        {/* 大学名称 - 使用纯黑色以获得最大可见度 */}
        <div className="text-center mt-8 relative z-30">
          <h1 className="text-4xl font-bold text-black tracking-wider" style={{textShadow: '0 0 2px rgba(255,255,255,1)'}}>STRATFORD INTERNATIONAL UNIVERSITY</h1>
        </div>
        
        {/* 证书标题 - 使用高对比度黑色 */}
        <div className="text-center mt-8 relative z-30">
          <h2 className="text-5xl font-bold text-black">CERTIFICATE</h2>
          <h3 className="text-3xl font-bold text-black mt-2">毕业证书</h3>
        </div>
        
        {/* 分隔线 - 使用更粗的分隔线增加可见度 */}
        <div className="my-6 border-t-4 border-black mx-16 relative z-30"></div>
        
        {/* 证书内容 - 增加字体大小和粗细 */}
        <div className="text-center relative z-30">
          <p className="text-2xl font-bold text-black">THIS CERTIFIES THAT</p>
          
          {/* 获得者姓名 - 增加突出显示底色及黑色边框 */}
          <div className="border-4 border-black py-3 px-6 mx-auto max-w-lg mt-4 bg-blue-50">
            <p className="text-4xl font-bold text-black">{certificate.name}</p>
          </div>
          
          <p className="text-2xl font-bold text-black mt-6">HAS COMPLETED THE PROGRAM</p>
          
          {/* 课程名称 - 使用深色边框增加对比度 */}
          <div className="border-4 border-black py-3 px-6 mx-auto max-w-lg mt-4 bg-yellow-50">
            <p className="text-3xl font-bold text-black">{certificate.course}</p>
          </div>
        </div>
        
        {/* 签名区域 - 提高可见度 */}
        <div className="flex justify-between mt-10 mx-16 pb-4 relative z-30">
          <div className="text-center">
            <div className="border-t-4 border-black w-40 mx-auto"></div>
            <p className="font-bold text-black mt-2 text-lg">University President</p>
          </div>
          
          <div className="text-center">
            <div className="border-t-4 border-black w-40 mx-auto"></div>
            <p className="font-bold text-black mt-2 text-lg">Program Director</p>
          </div>
        </div>
        
        {/* 日期和证书ID - 使用黑色字体确保可见度 */}
        <div className="text-center mt-4 relative z-30">
          <p className="font-bold text-black text-lg">
            Date: {new Date(certificate.date).toLocaleDateString()} | ID: {certificate.certificateId}
          </p>
        </div>
        
        {/* 添加备用水印，确保证书的正式性 */}
        <div className="absolute inset-0 flex items-center justify-center opacity-10 z-10">
          <div className="transform rotate-45">
            <p className="text-9xl font-bold text-black">SIU</p>
          </div>
        </div>
      </div>
      
      {/* 下载按钮区域 */}
      <div className="mt-6 flex space-x-4">
        <button
          onClick={downloadAsPDF}
          className="px-6 py-3 bg-blue-900 text-white font-bold rounded-md shadow-md hover:bg-blue-800 transition-colors"
        >
          下载PDF证书
        </button>
        
        <button
          onClick={downloadAsImage}
          className="px-6 py-3 bg-green-800 text-white font-bold rounded-md shadow-md hover:bg-green-700 transition-colors"
        >
          下载图片证书 (推荐)
        </button>
      </div>
    </div>
  );
};

export default HtmlCertificate;
